#include <stdio.h>
#include <stdlib.h>
#define MAX 2500
int compare(const void *a, const void *b) {
    return (*(int*)a - *(int*)b);
}
int longestArithmeticProgression(int arr[], int n) {
    int maxLen = 0;
    for (int i = 0; i < n; i++) {
        for (int j = i + 1; j < n; j++) {
            int diff = arr[j] - arr[i];
            int len = 2;
            int last = arr[j];
            for (int k = j + 1; k < n; k++) {
                if (arr[k] - last == diff) {
                    len++;
                    last = arr[k];
                }
            }
            maxLen = (maxLen > len) ? maxLen : len;
        }
    }
    return maxLen;
}
int main() {
    int n;
    scanf("%d", &n);
    int arr[n];
    for (int i = 0; i < n; i++) {
        scanf("%d", &arr[i]);
    }
    qsort(arr, n, sizeof(int), compare);
    printf("%d\n", longestArithmeticProgression(arr, n));
    return 0;
}

